INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('true-church', 'ceb', 'church-teaching', 'Matuod nga Iglesya', 'Igo na ba nga ang usa ka pundok nagdala sa ngalan ni Cristo aron tinuod gayod nga kini iya ni Cristo?', '"Ang Sta. Iglesya nagtudlo nga si Cristo sa dinhi pa siya sa kalibotan nagtukod ug usa ka Iglesya aron maoy mopadayon sa iyang bulohaton sa pagtudlo, pagdumala, ug pagbalaan sa iyang katawhan ug nga kini maila nato nga mao ang Iglesya Katolika. Ug si Cristo nagbutang diha sa iyang Iglesya sa upat ka timaan: Usa, santa, katolika, ug apostolika aron kini maila niadtong mangita niini gikan niadtong mga pundok nga tinukod lamang og tawo. Ang Sta. Iglesya mao ang makaylapon nga instrumento sa kaluwasan ug kinahanglan alang sa kaluwasan nga ang tawo mahidugtong niini. Kadtong nasayod nga ang Iglesya Katolika mao ang matuod nga Iglesya nga gitukod ni Cristo ug unya dili magpasakop niini, o kaha kadtong iyang mga sakop nga dili magpabilin kaniya dili maluwas. Alang sa iyang mga sakop kinahanglan ang ilang paglahutay hangtod sa kataposan kay kon dili mas sigpit ang paghukom nga himoon sa Dios tungod kay sila nakadawat man sa mas daghang mga grasya."'::jsonb, '[{"objection":"Igo na ba nga ang usa ka pundok nagdala sa ngalan ni Cristo aron tinuod gayod nga kini iya ni Cristo?","response":"Dili igo ang ngalan sa pag-ila sa tinuod. Si Cristo nagpasidaan nga dunay daghang nga magdala sa iyang ngalan aron pagpasalaag sa katawhan. “Pagbantay kamo ug ayaw kamo palimbong ni bisan kinsa, kay sa akong ngalan daghang tawo ang moanhi nga mag-ingon, ‘Ako ang Mesiyas!’ ug daghan ang malimbongan” (Mat. 24:4-5). “Kay manungha ang mga mini nga Mesiyas ug mga mini nga propeta; maghimo silag mga dagkong milagro ug mga katingalahan aron pagpasalaag sa mga pinili sa Dios, kon mahimo pa” (Mat. 24:24). “Dili ang tanan nga magtawag kanako ‘Ginoo, Ginoo,’ makasulod sa Gingharian sa langit… kon moabot na ang Adlaw sa Paghukom daghan unya ang moingon kanako, ‘Ginoo dili ba sa imong ngalan nagsangyaw man kami sa mensahe sa Dios, ug pinaagi sa imong ngalan gihinginlan namo ang mga yawa, ug naghimo kamig daghang mga milagro?’ Apan ako moingon unya kanila, ‘Wala ako makaila kaninyo. Pahawa kamong makasasala’” (Mat. 7:21-23). Bisan sa panahon sa mga apostoles nagsugod na pagtungha ang mga mini nga mga magtutudlo. “Dili sila matuod nga mga apostoles kondili mga mini nga namakak mahitungod sa ilang buhat ug nag-usab sa ilang kaugalingon aron mahisama gayod sila sa matuod nga mga apostoles ni Cristo” (2 Cor. 11:13). “Kining mga tawhana dili tinuod nga sakop sa atong pundok, busa namulag sila kanato. Kon tinuod pang ato silang mga kauban, magpabilin unta sila kanato. Apan namiya sila aron maila gayod nga sila dili kauban nato” (1 Jn. 2:19). “Motungha ang mga tawo nga magbiaybiay kaninyo- mga tawo nga nagsunod sa ilang mga daotang tinguha. Sila maoy hinungdan sa pagkabahinbahin” (Jud. 1:18-19)."},{"objection":"Unsaon man nato sa pag-ila ang matuod nga Iglesya?","response":"Dunay duha ka paagi sa pag-ila sa matuod nga Iglesya. Una- nga si Cristo gyod mismo ang iyang magtutukod ug Ikaduha- pinaagi sa iyang mga timaan. Ang pagtukod sa Iglesya gipahibalo nang daan sa mga propeta. “Sa panahon niining mga haria ang Dios magtukod ug usa ka gingharian nga dili gayod malumpag” (Dan. 2:44). Natuman kini sa pag-abot ni Cristo, “Ikaw si Pedro ug sa ibabaw niining bato tukoron ko ang akong iglesya, ug bisan gani ang mga ganghaan sa hades dili makabuntog niini” (Mat. 16:18). Dinhi atong masabot nga ang matuod nga Iglesya, 1) tinukod ni Cristo, 2) gitukod kini ni Cristo diha ni Pedro ug sa iyang mga sumusunod isip makita nga pangulo ug 3) nga ang iyang iglesya mapadayonon ug walay pagkahanaw. Nga ang Iglesya Katolika lamang ang naghupot niining tulo ka kalipikasyon sa matuod nga Iglesya sayon kaayong kapamatud-an. Nga ang Iglesya Katolika tinukod ni Cristo gipamatud-an sa mga referencia kun basahon sa kasaysayan nga walay gilabanan. Ania ang mabasa: “Iglesya Katolika- ang kinatibuk-an nga termino nga gigamit pagpasabot sa kapunongan nga gitukod ni Cristo ug gipadad-an sa Espiritu Santo sa adlaw sa Pentecostes. Mao kini ang kapunongan sa mga magtutuo nga nahiusa ubos sa Obispo sa Roma ug busa gitawag usab kini og Romano Katolika nga Simbahan” (Grolier’s Encyc. Vol. 5 p 106). “Ang Iglesya Katolika adunay duha ka kinaiya, tawhanon ug diosnon, sama kang Cristo nga iyang magtutukod” (International Encyc. Vol 15 p 520). Nga ang Iglesya Katolika lamang ang miila ni Pedro nga pangulo ug padayon nga gidumalahan sa iyang mga sumusunod makita nato sa lista sa walay bugto nga kutay sa mga Sto. Papa nga nagsugod ni Pedro. “Si Pedro taga-Betsaida sa Galilea, prinsipe sa mga apostoles ang unang papa. Nakapuyo sa unang panahon sa Antioquia ug nga nakapuyo sulod sa 25 ka tuig sa Roma diin gipatay siya nga namartir sa tuig 64 o 67 AD” (World Almanac Ed. 1963 p 298). “Mimatuod nga si San Pedro mao ang unang Papa sa Iglesya Katolika ug una sa tanan niyang mga Santo Papa” (Information Almanac Ed. 1968 p 296). Nga ang Iglesya Katolika dunay walay bugto nga kasaysayan nga mapaatras nato sa panahon sa mga apostoles gipamatud-an sa mga standard references. “Usa kini ka dili malalis nga tinuod nga ang bugtong Iglesya nga makasubay sa iyang kasaysayan ngadto sa panahon sa mga apostoles mao ang Iglesya Katolika” (Encyc. Micro. Brit. Vol 8 p. 664). Bisan ang atong mga kaatbang sa pagtuo napugos sa pag-angkon niini, “Bisan ang kasaysayan sa kalibotan nagpakita sa direkta nga kadugtongan sa panahon tali sa Iglesya Katolika ug sa mga apostoles ug kini mohatod sa paghukom nga ang Iglesya Katolika mao ang matuod nga Iglesya nga tinukod ni Cristo” (Pasugo July-August 1988 p. 6)."},{"objection":"Unsa man ang mga timaan sa matuod nga Iglesya?","response":"Ang matuod nga Iglesya naghupot sa upat ka mga timaan:\nUna- Usa ug panaghiusa. Kini nagpasabot nga si Cristo nagtukod og usa lamang ka iglesya dili daghan ug niining maong iglesya anaa ang panaghiusa. Si Jesus nag-ampo, “Balaang Amahan, bantayi sila diha sa gahom sa imong ngalan- ang ngalan nga imong gihatag kanako, aron sila mausa ingon nga ikaw ug ako usa lamang” (Jn. 17:11). Nalakip niini kining mosunod: a) kahiusahan sa pagtuo- nga ang tanang mga sakop nagtuo sa managsama nga pagtulon-an, “May usa lamang ka lawas ug usa ka Espiritu, ingon nga may usa lamang ka paglaom… May usa lamang ka Ginoo, usa ka pagtuo” (Efeso 4:4-5). “Ang tinuod, walay ‘laing ebanghelyo,’ apan gisulti ko kini kay may mga tawo man nga nagsamok kaninyo ug naninguha pagtuis sa ebanghelyo ni Cristo…kon may magwali kaninyo ug ebanghelyo nga lahi sa inyong nadawat, matinunglo siya” (Gal. 1:6-8). b) kahiusahan sa pagdumala- nga ang tanan nagkahiusa sa pagpailawom sa makita nga pangulo nga gibilin ni Cristo, “mahimo silang usa na lamang ka panon ubos sa usa ka magbalantay” (Jn. 10:16). Ug si Cristo miingon ngadto ni Pedro, “Atimana ang akong mga nating karnero… Atimana ang akong mga karnero” (Jn. 21:15-17). c) kahiusahan sa pagsimba- ang tanan nagkahiusa sa usa ka paagi sa pagsimba pinaagi sa usa lamang ka sakripisyo, “Ug gigamit nila ang ilang panahon pagpamati sa mga gitudlo sa mga apostoles,… ug sa pagpikaspikas sa tinapay ug sa mga pag-ampo” (Buh. 2:42). “Sanglit may usa lamang ka pan, kitang tanan bisan daghan, usa lamang ka lawas; kay nakig-ambit man kita sa usa lamang ka pan” (1 Cor. 10:17). Ang Iglesya Katolika naghupot sa kahiusa diha sa pagtuo pinaagi sa Credo ug sa iyang katesismo, kahiusa sa pagdumala pinaagi sa iyang mga ka-obispohan ug sa Sto. Papa, kahiusa sa pagsimba pinaagi sa iyang liturhiya diin anaa ang pagbasa sa Biblia, ang pagsaulog sa mga sacramento ug sa Santos nga Misa.\nIkaduha- Santa kun balaan. “Apan kamo mao ang piniling katawhan, ang mga harianong pari, ug ang balaang nasod” (1 Ped. 2:9). Ang Iglesya balaan gumikan niini nga mga katarungan: a) Si Cristo nga iyang magtutukod balaan og tinubdan sa pagkabalaan, “Kon balaan ang unang tipik sa pan nga gihalad ngadto sa Dios, balaan usab ang kinatibuk-an niini; ug kon balaan ang mga gamot sa kahoy, balaan usab ang mga sanga” (Rom. 11:16). b) Ang Iglesya nagtudlo og balaan nga mga pagtulon-an. Si Jesus mimando, “tudloi sila sa pagtuman sa tanan nga akong gisugo kaninyo” (Mat. 28:20). c) Ang Iglesya naghupot sa kahimanan sa pagkabalaan nga mao ang mga sacramento nga gitukod ni Cristo, “Isipa kami nga mga sulugoon ni Cristo nga gitugyanan sa mga tinagong kamatuoran sa Dios” (1 Cor. 4:1). d) Ang Iglesya mamungag mga santos “ug gipili ko kamo aron manlakaw ug mamungag daghan- mga bunga nga molungtad” (Jn. 15:16). Ang Iglesya Katolika nakapadangat na sa daghan niyang mga sakop gikan sa lainlaing kahimtang sa kinabuhi ug sa matag panahon ngadto sa pagka-santos, mga tawo nga naila sa kabalaan sa ilang kinabuhi ug gimatud-an sa Dios pinaagi sa mga milagro ug busa gituboy ngadto sa kadungganan sa altar ug sa dili maihap niya nga mga sakop nga tua na karon sa langit. Apan wala usab kini magpasabot nga ang tanan niyang mga sakop o bisan ang iyang mga pangulo pulos na sab santos tungod kay si Jesus nagtudlo nga ipon sa iyang panon anaa usab ang mga makasasala, “Ang Gingharian sa langit sama usab sa usa ka baling nga gitaktak didto sa lanaw, nga nakakuha sa tanang matang sa isda” (Mat. 13:47). Wala isalikway sa Sta. Iglesya ang masalaypon niyang mga sakop tungod kay ang iyang misyon sama man sa misyon ni Jesus nga “wala moanhi aron sa pagtawag sa mga matarong kondili sa mga makasasala aron sila maghinulsol” (Mat. 9:13).\nIkatulo- Katolika kun makaylapon. Si Jesus miingon, “Busa panlakaw kamo ngadto sa tanang katawhan sa tibuok kalibotan ug himoa sila nga akong mga tinun-an, ug bunyagi sila sa ngalan sa Amahan, sa Anak ug sa Espiritu Santo, ug tudloi sila pagtuman sa tanan nga akong gisugo kaninyo. Ug hinumdomi! Ako mag-uban kaninyo kanunay hangtod sa kataposan sa kalibotan” (Mat. 28:19-20). Dinhi masabot nato ang pagka-katolika sa matuod nga Iglesya: a) katolika sa dapit “panlakaw kamo ngadto sa tanang katawhan sa tibuok kalibotan,” b) katolika sa pagtulon-an “tudloi sila sa pagtuman sa tanan nga akong gisugo kaninyo” ug c) katolika sa panahon “Ako mag-uban kaninyo kanunay hangtod sa kataposan sa kalibotan.” Ang pagka-katolika sa matuod nga Iglesya dili absoluto tungod kay duna may mga tawo nga mosalikway sa kamatuoran, “kay wala man nila dawata ug higugmaa ang kamatuoran nga makaluwas unta kanila” (2 Tes. 2:10) kondili moral nga nagpasabot nga daghan ang mopasakop kaniya, “Sa umaabot nga mga adlaw ang bukid diin nahimutang ang Templo mahimong labing taas sa tanan… Daghang kanasoran mag-ambahan sa pag-adto didto” (Isa. 2:2).\nIkaupat- Apostolika. Kini nagpasabot nga ang matuod nga Iglesya adunay walay bugto nga kutay sa iyang mga pangulo nga naggikan sa mga apostoles. Ang mga apostoles gihimo ni Cristo nga mga pangulo sa iyang Iglesya, “Gitukod kamo diha sa sukaranan nga mao ang mga apostoles” (Efeso 2:20) ug sila gisul-oban ni Jesus sa gahom sa pagtudlo, sa pagdumala ug pagbalaan, “Ingon nga gipadala ako sa Amahan, ako usab nagpadala kaninyo” (Jn. 20:21). Apan taliwala sa mga apostoles gipili ni Cristo si Pedro isip maoy labaw nga tigdumala sa iyang panon, “Ikaw si Pedro ug sa ibabaw niining maong bato tukoron ko ang akong Iglesya ug bisan gani ang mga ganghaan sa hades dili makabuntog niini. Ihatag ko kanimo (ngadto ni Pedro) ang mga yawi sa gingharian sa langit. Ang imong gapuson dinhi sa yuta gapuson usab didto sa langit ug ang imong hubaran sa yuta mahinubaran usab didto sa langit” (Mat. 16:18-19). Busa ang mga apostoles nga gipadala ni Cristo nanlakaw ngadto sa lainlaing dapit dili ingon nga mga tawo nga walay kadugtongan sa usag-usa kondili ubos kanunay ni Pedro isip labawng pangulo. Si San Anselmo miingon, “Ubi Petrus, ibi Ecclesia” nga ang hubad mao kini: Diin gani atua si Pedro nagdumala pinaagi sa iyang mga sumusunod (nga mao ang Sto. Papa), atua didto ang Iglesya. Ug kadtong kagahoman sa pagtudlo, pagdumala ug pagbalaan gipasa sa mga apostoles ngadto sa ilang mga sumusunod (nga mao ang ka-Obispohan), “Sa matag iglesia nagtudlo sila ug mga pangulo; ug uban sa mga pag-ampo ug pagpuasa ilang gitugyan sila ngadto sa Ginoo” (Buh. 14:23). Dinhi atong makita ang mga misunod pinili niadtong nag-una kanila."}]'::jsonb, '["Mat. 24:4-5","Mat. 24:24","2 Cor. 11:13","1 Jn. 2:19","Jud. 1:18-19","Dan. 2:44","Mat. 16:18","Jn. 17:11","Efeso 4:4-5","Gal. 1:6-8","Jn. 10:16","Jn. 21:15-17","Buh. 2:42","1 Cor. 10:17","1 Ped. 2:9","Rom. 11:16","Mat. 28:20","1 Cor. 4:1","Jn. 15:16","Mat. 13:47","Mat. 9:13","Mat. 28:19-20","2 Tes. 2:10","Isa. 2:2","Efeso 2:20","Jn. 20:21","Mat. 16:18-19","Buh. 14:23"]'::jsonb, '["true church"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.042Z')
