INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('holy-trinity', 'ceb', 'church-teaching', 'Santisima Trinidad', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa santisima trinidad?', '"Ang Sta. Iglesya nagtudlo nga adunay usa lamang ka Dios apan niining usa ka pagka-Dios adunay tulo ka managlahi nga personas: ang Amahan, ang Anak ug ang Espiritu Santo. Ang Amahan Dios nga walay gigikanan. Ang Anak Dios nga gikan sa Amahan. Ang Espiritu Santo Dios nga gikan sa Amahan ug sa Anak. Ang matag usa kanila naghupot sa bug-os nga kahimtang o kinaiya sa pagka-Dios. Kun unsang pagka-unsaa nga sa usa ka Dios adunay tulo ka mga personas ug kon ngano nga ang tulo ka managlahi nga personas usa ra diha sa pagka-Dios kabahin kini sa misteryo sa Trinidad nga dili gyod matugkad sa atong pangisip. Apan ang doktrina sa Santisima Trinidad atong masabot tungod kay ang gikinahanglan niini mao man ang paghibalo sa kahulogan sa mga pulong nga gigamit sa pagsaysay sa maong doktrina. Ang kinaiya kun “nature” mao ang lintunganay’ng hiyas sa usa ka butang. Mao kini ang nakapamao sa butang nga ginganlan. Ang kinaiya mao usab ang makapahimo sa usa ka pagkamao nga molihok isip mao nga pagkamao pananglit ang nakapahimo sa tawo sa paglihok isip tawo nagsukad sa iyang kinaiya sa pagka-tawo. Ang kinaiya sa pagka-Dios mao ang iyang paglungtad sa iyang kaugalingon “self-existent” ug wala siya mag-agad sa lain sa iyang pagkanaa. Dugang pang lintunganay’ng hiyas sa pagka-Dios mao ang iyang pagkamakagagahom, pagkanahibalo sa tanan, pagkanaa sa tanan ug pagkawalay sinugdanan ug walay kataposan. Mao kini ang gihiusahan sa Amahan, Anak ug Espiritu Santo. Ang “persona” nagkahulogan sa pagkamao nga dunay salabutan ug kabubut-on. Ang Amahan, Anak ug Espiritu Santo ang matag usa kanila adunay salabutan ug kabubut-on busa ang matag usa kanila matawag nga persona.\nAng pagtulon-an labot sa Santisima Trinidad gipasabot diha sa Daang Tugon. Sa pagbuhat sa Dios sa tawo siya namulong: “buhaton nato ang tawo sama sa atong larawan ug panagway” (Gen. 1:26). Dinhi masabot nga ang Amahan dunay kauban sa pagpamuhat tungod sa paggamit sa plural nga personal pronoun nga “nato.” Sa pagpakanaog sa Dios sa iyang silot sa katawhan nga buot magtukod ug tore nga mosangko sa langit siya miingon, “manaog kita ug libogon ta ang ilang pinulongan” (Gen. 11:7). Sa pagtawag sa Dios ni Propeta Isaias siya miingon, “Kinsa man akong ipadala? Ug kinsa man ang moadto alang kanamo?” (Isa. 6:8). Ug si Propeta Isaias miingon nga “ang Dios ug ang iyang Espiritu maoy nagpadala kanako” (Isa. 48:16). Apan diha sa Daang Tugon salabtonon kaayo ang mga teksto nga nagpasabot nga diha sa Dios adunay kapin sa usa ka persona busa kining maong mga pasahe kinahanglan nga pagasabton sa pagpadayag sa Dios diha sa Bag-ong Tugon. Timan-an usab nato nga ang Dios mipadayag sa iyang kaugalingon sa inanay nga paagi. Ang gipahimug-atan nga pagtulon-an sa Daang Tugon mao ang pagka-ulosahon sa Dios. Maingon usab nato nga niadtong panahona dili pa andam ang katawhan sa pagpadayag sa misteryo sa Trinidad tungod kay naglibot kanila ang daghang mga nasod nga nag-ila ug daghang mga dios ug busa dako’g posibilidad nga masinayop kini sa pagsabot nga dunay tulo ka Dios.\nDiha sa Bag-ong Tugon, ang pagtulon-an labot sa Santisima Trinidad gipadayag sa upat ka hinungdanon nga bahin sa kinabuhi ni Jesus. Una- sa iyang pagpakatawo. Sa plano sa Dios sa pagpanubos ang ikaduhang persona sa Santisima Trinidad magpakatawo pinaagi sa usa ka babaye. Ug taliwala sa kababayenhan si Sta. Maria ang gipili sa Dios busa kinahanglan nga masayod siya kon kinsa ang iyang isabak. Ang anghel miingon ngadto ni Maria, “mokunsad kanimo ang Espiritu Santo ug ang gahom sa Dios magpabilin diha kanimo. Tungod niini ang balaan nga bata pagatawgon nga Anak sa Dios” (Luc. 1:35). Ikaduha- sa pagbunyag kang Jesus. Tapos kabunyagi si Jesus, nakita ni San Juan nga naabli ang langit ug ang Espiritu Santo nagpakita sa dagway sa usa ka salampati ug dunay tingog nga nabati gikan sa langit nga nag-ingon “kini ang pinangga kong Anak nga gikahimut-an ko pag-ayo” (Luc. 3:22). Ikatulo- sa gabii sa pagpasakit ni Jesus. Siya misaad sa iyang mga tinun-an, “Mangayo ko sa Amahan ug iyang ipadala kaninyo ang laing Manlalaban, ang Espiritu sa kamatuoran” (Juan 14:16). Ikaupat- sa dayong saka ni Jesus ngadto sa langit. Si Jesus mimando sa iyang mga tinun-an, “panlakaw kamo ngadto sa tibuok kalibotan ug himoa sila nga akong mga tinun-an, ug bunyagi sila sa ngalan sa Amahan, sa Anak ug sa Espiritu Santo” (Mat. 28:19). Niining mga pulonga gibutang ni Jesus ang Espiritu Santo sa samang gahom, dungog ug himaya sa Amahan ug sa Anak.\nAng mga Apostoles sa ilang pagwali kanunay nga naghisgot sa suod nga kadugtongan sa tulo ka mga personas. Sa adlaw sa Pentecostes si San Pedro namulong, “Ang tagsatagsa kaninyo kinahanglan nga maghinulsol, ug magpabunyag sa ngalan ni Jesu-Cristo aron pasayloon ang inyong mga sala, ug madawat ninyo ang gasa sa Dios nga mao ang Espiritu Santo” (Buh. 2:38). Sa pagtapos ni San Pablo sa iyang sulat ngadto sa taga-Corinto mihatag siya kanila’g panalangin sa pag-ingon, “Mag-uban unta kaninyong tanan ang grasya sa Ginoong Jesu-Cristo, ang gugma sa Dios, ug ang pagpakig-ambit sa Espiritu Santo” (2 Cor. 13:13). Si San Pedro naghisgot nga ang atong pagkatinawag maoy pag-ambit sa kinabuhi sa Trinidad, “Gipili kamo sumala sa tuyo sa Dios nga Amahan ug gihimong balaang katawhan pinaagi sa iyang Espiritu aron magmasinugtanon kamo kang Jesu-Cristo ug mahinloan sa iyang dugo” (1 Ped. 1:2). Ug si San Judas Apostol nagpahimangno, “Pag-ampo kamo diha sa gahom sa Espiritu Santo, ug pagpabilin kamo sa gugma sa Dios samtang naghulat kamo sa atong Ginoong Jesu-Cristo nga sa iyang kaluoy maghatag kaninyo sa kinabuhing walay kataposan” (Jud. 1:20-21).\n\nDiha sa Biblia ang matag persona gipaila nga Dios. Mahitungod sa Amahan, si San Pablo miingon, “apan alang kanato may usa lamang ka Dios, ang Amahan nga nagbuhat sa tanang butang” (1 Cor. 8:6). Ug sa sulat ngadto sa taga-Hebreo ang Amahan mismo mipaila sa iyang Anak nga Dios, “Apan bahin sa iyang Anak, miingon ang Dios, ‘Ang imong trono, O Dios, molungtad hangtod sa kahangtoran” (Heb. 1:8). Si San Pedro nagtudlo nga ang Espiritu Santo Dios, “ug namakak sa ka Espiritu Santo… Dili ang mga tawo ang imong gibakakan kondili ang Dios.” Bisan kon ang matag persona gipaila nga Dios apan dili sila tulo ka pagka-Dios kondili usa ra ang ilang pagka-Dios. Si Jesus miingon, “Ang akong Amahan ug ako usa ra” (Juan 10:30). Sa sulat ni San Juan giingon, “didto sa langit dunay tulo nga nagpamatuod: ang Amahan, ang Pulong ug ang Espiritu. Ug kining tulo usa lamang” (1 Juan 5:7). Ang pulong Trinidad dili mabasa letra por letra sa Biblia apan ang kahulogan sa maong pulong tukma sa gitudlo sa Biblia!\n\nSunod mohimo kita’g panagtandi tali sa kahimtang sa Dios, ni Cristo ug sa Espiritu Santo. Kon ang mga lintunganay’ng hiyas sa pagka-Dios gihuptan usab ni Cristo ug sa Espiritu Santo masabot nato nga sila matuod nga Dios. Una- ang pagka-Magbubuhat: “ang Dios maoy nagbuhat sa tanang butang” (Heb. 3:4). Apan si Jesus miingon, “Ang tanan nga gibuhat sa Amahan gibuhat usab sa Anak” (Juan 5:19). Ug sa paglalang sa Dios sa tanang butang giingon, “Sa pagsugod pagbuhat sa Dios sa kalibotan ug sa tanang butang sa kalangitan… ang Espiritu sa Dios naglihok ibabaw sa katubigan” (Gen. 1:1-2). Busa ang Espiritu Santo apil sa pagpanglalang. Ikaduha- ang pagka-Eternal: “sa wala pa buhata ang kabukiran Dios ka na sukad sa walay sinugdan ug walay kataposan” (Sal. 90:2). Mahitungod sa Mesiyas nga gitagna nga matawo sa Betlehem giingon nga ang iyang kagikan “sukad sa kakaraanan, sukad sa walay sinugdan ug walay kataposan” (Miq. 5:2). Labot sa Espiritu Santo giingon, “Pinaagi sa walay kataposang Espiritu (sa Ininglis “Eternal Spirit”) gihalad niya ang iyang kaugalingon ingon nga hingpit nga halad” (Heb. 9:14). Ikatulo- ang pagka-Omniscient: “Ang Labing Halangdon nahibalo sa tanang butang nga mahibaloan ug nakasabot sa mga timaan sa katuigan” (Sir. 42:18). Ug mahitungod kang Cristo, “Diha kaniya natago ang tanang bahandi sa kaalam ug kahibalo sa Dios” (Col. 2:3). Ug matod ni San Pablo, “Ang Espiritu nagsusi sa tanang mga butang, bisan pa niadtong labing natago nga mga katuyoan sa Dios” (1 Cor. 2:10). Ikaupat- ang pagka-Omnipresent: “Ako ang Dios nga anaa sa tanang dapit” (Jer. 23:24). Ug labot ni Cristo, “Busa siya nga mikunsad mao ra usab ang mikayab saylo pa sa kalangitan, aron mapuno ang tibuok uniberso sa iyang presensya” (Efeso 4:10). Ug sa basahon sa mga Salmo, “Asa ba ako paingon aron mahilayo sa imong Espiritu? Asa ba ako motago aron mahilayo sa imong presensya?” (Sal. 139:7-10). Ikalima- ang pagka-Tinubdan sa kinabuhi: “Tinubdan ka sa tanang kinabuhi..” (Sal. 36:9). Ug si Jesus miangkon’ “Kay ingon nga banhawon sa Amahan ang mga patay ug hatagag kinabuhi, banhawon usab sa Anak ug hatagag kinabuhi ang buot niyang banhawon” (Jn. 5:21). Ug labot sa Espiritu Santo si Job miingon, “Ang Espiritu sa Dios maoy nagbuhat kanako ug naghatag kanakog kinabuhi” (Job. 33:4). Ikaunom- ang pagka-Makagagahom: “Ginoo, wala gayoy sama kanimo. Ikaw makagagahom ug halangdon, gamhanan ang imong ngalan” (Jer. 10:6). Si San Pablo miingon, “si Cristo mao ang gahom ug ang kaalam sa Dios” (1 Cor. 1:24). Ug si Jesus miingon, “Dili si Satanas kondili ang Espiritu sa Dios maoy naghatag kanako sa gahom” (Mat. 12:28). Pinasikad niini nga panagtandi tin-aw nga ang Amahan, Anak ug Espiritu Santo naghupot sa usa ra ka kinaiya o kahimtang sa pagka-Dios!\nBisan kon kining maong kamatuoran gipadayag kanato apan nagpabilin kini nga mao ang labing halawom ug labing tulugkaron nga misteryo sa atong pagtuo, “Makatukib ka ba sa mga utlanan sa pagkagamhanan sa Dios? Mas habog pa kini sa langit ug dili mo gayod kini matugkad” (Job. 11:7-8). Si San Pablo miingon, “Pagkabahandianon gayod sa Dios ug pagkatulugkaron sa iyang kaalam ug kahibalo! Kinsay makasaysay sa iyang hukom? Kinsay makasabot sa iyang mga paagi?” (Rom. 11:33). Atubangan niining maong misteryo ang atong mahimo mao ang pagpaubos, ang pagpasalamat ug pagdayeg sa himaya sa Dios. Ang atong kinabuhi usa ka paghalad ngadto sa Santisima Trinidad. Sa pagsulod nato sa atong espirituhanong kinabuhi gibunyagan kita sa ngalan sa Amahan, sa Anak ug sa Espiritu Santo. Sa dili pa kita mobuhat bisag unsa manguros kita uban sa pag-ingon “Sa ngalan sa Amahan, ug sa Anak ug sa Espiritu Santo.” Diha sa liturhiya modungan kita sa mga anghel sa kalangitan sa pag-ingon, “Himaya sa Amahan, sa Anak ug sa Espiritu Santo.”"'::jsonb, '[]'::jsonb, '["Gen. 1:26","Gen. 11:7","Isa. 6:8","Isa. 48:16","Luc. 1:35","Luc. 3:22","Juan 14:16","Mat. 28:19","Buh. 2:38","2 Cor. 13:13","1 Ped. 1:2","Jud. 1:20-21","1 Cor. 8:6","Heb. 1:8","Juan 10:30","1 Juan 5:7","Heb. 3:4","Juan 5:19","Gen. 1:1-2","Sal. 90:2","Miq. 5:2","Sir. 42:18","Col. 2:3","1 Cor. 2:10","Jer. 23:24","Efeso 4:10","Sal. 139:7-10","Sal. 36:9","Jn. 5:21","Job. 33:4","Jer. 10:6","1 Cor. 1:24","Mat. 12:28","Job. 11:7-8","Rom. 11:33"]'::jsonb, '["holy trinity"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.042Z')
