INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('primacy-of-peter', 'ceb', 'papacy', 'Ang Pagkapangulo ni Pedro', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa ang pagkapangulo ni pedro?', '"Ang Sta. Iglesya nagtudlo nga si Cristo naghatag ngadto ni Pedro sa labawng gahom ug katungod sa pagdumala sa iyang Iglesya ug ang maong katungdanan gihuptan sa iyang mga sumusunod nga mao ang Obispo sa Roma kun Sto. Papa. Busa, aron mahimong tinuod nga sumusunod ni Cristo ang tanang mga kristohanon, ang mga kaparian ug ang mga layko, kinahanglan nga mahiusa sa pangagamhanan sa Roma, diin si Pedro nagdumala diha sa iyang mga sumusunod. Ang Sta. Iglesya nagtudlo pa gayod nga ang Sto. Papa, kon siya manudlo ginamit ang iyang katungdanan isip sumusunod ni San Pedro ug labawng pangulo sa tibuok Simbahan mahitungod sa tulohoan ug moralidad alang sa tanang mga katoliko dili siya masayop sa iyang pagpanudlo pinaagi sa talagsaong panalipod sa Espiritu Santo nga gisaad ni Cristo.\n\nSa Daang Tugon ang katawhan sa Israel dunay makita nga pangulo. Aron paghusay sa kagubot tali kanila wala sila mo-apilar direktamente sa Kasulatan kondili dunay labawng pari nga gipili sa Dios isip maoy labawng maghuhukom alang sa iyang katawhan (Deut. 17:8-12). Sa ilang paglingkawas gikan sa Ehipto si Moises ang giila nga pangulo (Exo. 33:12-14) ug si Josue maoy nahimong pangulo puli ni Moises (Deut. 31:1-8). Bisan kon ang Dios maoy matuod nga pangulo sa iyang katawhan (Sal. 136:16) apan duna gyoy makita nga pangulo nga iyang gipili.\n\nSa Bag-ong Tugon ang Iglesya mao ang bag-ong katawhan sa Dios diin si Cristo mao ang dili makita ug espirituhanon nga pangulo (Col. 1:18). Apan kining pagkapangulo ni Cristo iya kining gilugway ngadto ni Pedro isip makita nga pangulo sa iyang Iglesya inigsaka na niya sa langit. Si Pedro ang gihatagan niya sa mga yawi sa gingharian sa langit, “Ikaw mao si Pedro ug sa ibabaw niining maong bato pagatukoron ko ang akong Iglesya ug bisan gani ang ganghaan sa hades dili makabuntog niini. Ihatag ko kanimo ang mga yawi sa gingharian sa langit, ang imong gapuson dinhi sa yuta gapuson usab didto sa langit ug ang imong hubaran dinhi sa yuta mahinubaran usab didto sa langit” (Mat. 16:19). Ug kining mga yawi nagpasabot sa gahom kun autoridad sa pagkapangulo, “sul-oban ko siya sa imong bisti, ug baksan ko siya sa imong bakos, ug itugyan ko kaniya ang imong gahom; mahimo siyang pangulo sa mga molupyo sa Jerusalem ug sa Juda. Ug ihatag ko kaniya ang mga yawi sa balay ni David; siyay moabli niini ug walay makasira; mosira niini ug walay makaabli” (Isa. 22:21-22). Si Jesus miangkon nga siya mao ang “maayong magbalantay sa panon” (Jn. 10:16) ug sa wala pa siya mosaka sa langit siya mitugyan sa tibuok panon- mga karnero ug mga nating karnero- ngadto sa pag-atiman ni Pedro (Jn. 21:15-17). Ang mga karnero nagpasabot sa katawhan sa Dios (Sal. 79:13) ug ang magbalantay pangulo sa panon (Jer. 25:34). Si Pedro ang mopasib-sib dili lamang sa mga nating karnero (mga layko) kondili lakip usab sa mga karnero (obispo ug mga kaparian). Sa unsa man? Dayag na lang nga sa lonsay nga pagtulon-an!\nDiha sa Daang Tugon giusab sa Dios ang ngalan ni Abram ngadto sa Abraham sa dihang iya siyang gipili aron mahimong amahan sa usa ka dakong nasod (Gen. 17:5). Sa Bag-ong Tugon giusab ni Jesus ang ngalan ni Simon ngadto sa Pedro (Aramaico “Kephas”) nga sa ato pa batong bantilis (Jn. 1:42). Unsa may tuyo sa pag-usab sa maong ngalan? Aron pagpasabot nga diha ni Pedro- isip makita nga pangulo- ipatukod ni Cristo ang iyang Iglesya. Si Cristo mao ang magtutukod sa balay (Mat. 7:24) ug ang balay nagkahulogan sa Iglesya (1 Tim. 3:15) ug gibut-an ni Jesus ang pagtukod niini diha ni Pedro (Mat. 16:18). Ang maong katungdanan wala mohunong pagkamatay ni San Pedro tungod kay ang Iglesya dili man mahanaw (Mat. 28:20) busa nahipasa kini ngadto sa iyang mga susmusunod tungod kay dili nato mahunahuna nga motukma kini sa Diosnong kaalam nga pasagdan ni Cristo ang iyang katawhan nga walay makita nga mangulo kanila! Sa gabii sa iyang pagpasakit si Cristo mihimo siya og pinasahi nga pag-ampo ug pasalig nga ang pagtuo ni Pedro (sa ato pa ang iyang panudlo) dili mabuntog ug siya ang molig-on sa iyang mga igsoon sa pagtuo (Luc. 21:31-32). Ngano man? Tungod kay si Cristo nasayod nga diha ni Pedro mahisandig ang kabudlay sa pagdumala sa tibuok Iglesya. Sa iyang unang sulat si San Pedro nag-awhag sa mga kaobispohan niadtong panahona, “Naghangyo ako sa mga pangulo diha sa inyong iglesia, ingon nga ako pangulo usab sama kaninyo” (1 Ped. 5:1). Kini nga pagpahimangno sa mga pangulo diha sa iglesia mahimo lamang sa labaw nga pangulo diha sa panon ni Cristo!\nDiha sa mga Buhat sa mga Apostoles nga maoy nagtali sa mga panghitabo human si Cristo misaka sa langit makita nato ang nag-una nga papel nga gihuptan ni Pedro: sa pagpili sa mopuli ni Judas ang iyang sugyot gitamod sa iyang mga kauban (Buh. 1:16); siya ang unang miwali sa adlaw sa Pentecostes samtang ang iyang mga kauban namati kaniya (Buh. 2:14-41); mihimo siya sa unang milagro (Buh. 5:15); mibarog siya nga maghuhukom kang Ananias ug Saphira (Buh. 5:1-11); siya usab ang mipakanaog sa hukom ngadto kang Simon Magus (Buh. 8:20-21); siya ang mihukom sa pagdawat ni Cornelio (Buh. 10:4-5) ug sa mga Gentil nga nangakabig (Buh. 11:1-18); sa dihang siya napreso, ang tibuok Iglesya nag-ampo alang kaniya (Buh. 12:5); siya ang mihusay sa kagubot didto sa konsilyo sa Jerusalem ug ang iyang mga kauban miuyon kaniya (Buh. 15:7). Kini nga mga pruyba igo na kining momatuod ngadto sa matinud-anon nga mobasa sa Biblia labot sa pagkapangulo ni Pedro."'::jsonb, '[{"objection":"Dili si Pedro maoy pangulo sa Iglesya kondili si Cristo, “si Cristo ang ulo sa Iglesya nga mao ang iyang lawas” (Col. 1:18).","response":"Si Cristo mao ang nagpabilin nga espirituhanon ug dili makita nga pangulo (Col. 1:18) apan ang iyang pagkapangulo iyang gilugway ngadto ni Pedro isip makita nga pangulo (Mat. 16:19)."},{"objection":"Ang Biblia klaro nga nagtudlo, dili nga ang Iglesya gitukod diha ni Pedro, kondili nga “ang bato nga sukaranan mao si Cristo” (Efeso 2:20)","response":"Tinuod nga si Cristo mao fundamento nga bato nga sukaranan (Efeso 2:20) ug si Pedro gihimo ni Cristo nga “kephas=bato” nga lugway kaniya (Jn. 1:42) busa wala kini sumpaki."},{"objection":"Ang ‘petros’ nga mao si Pedro dili mahitabo nga patukoranan tungod kay nagkahulogan kini ug gamay nga bato kondili Petra nga nagpasabot sa pagtuo nga gipadayag ni Pedro (Mat. 16:16,18).","response":"Ang petros ang gigamit sa griego pagpasabot ni Pedro ug dili ang Petra tungod kay si Pedro lalaki man. Apan sa aramaico ang gisulti ni Jesus mao kini: “Ikaw si Kepha ug si ibabaw niining Kepha pagatukoron ko ang akong iglesya” (Mat. 16:18). Klaro nga ang bato nga gipasabot ni Cristo mao si Pedro."},{"objection":"Kadtong mga yawi nga nadawat ni Pedro wala maghimo kaniya nga labaw sa ubang mga apostoles tungod kay sila usab nakadawat sa maong katungod (Mat. 18:18).\nSupak 5 . Si Jesus mitawag ni Pedro og satanas (Mat. 16:23) busa klaro nga si Jesus wala gayod maghimo ni Pedro nga pangulo.","response":"Nadawat sa ubang mga apostoles ang gahom sa pagdili ug pagtugot sumala sa katungdanan nga gitugyan ni Cristo sa matag usa kanila isip mga kauban ni Pedro sa pagdumala sa panon ni Cristo apan nadawat ni Pedro ang maong gahom alang sa tibuok Iglesya nga gitugyan ni Cristo ngadto kaniya (Mat. 16:18-19, Jn.21:15-17)."},{"objection":"","response":"Ang pulong satanas sa hebreo “satana” nagpasabot og babag. Ang tawhanong pagbati ug hunahuna ni Pedro maoy wala mahitukma sa plano ni Jesus sa pagpanubos (Mat. 16:21, 23) apan dili sabton nga iyang gikuhaan sa katungod si Pedro sama nga si Jesus sa ubang mga okasyon mibadlong usab sa mga apostoles sa walay pagkuha sa ilang katungod sa pagkapinili."},{"objection":"Ang labaw mao ang mopadala, apan si Pedro gipadala sa ubang mga apostoles ngadto sa Samaria kuyog ni Juan busa wala siya ilha nga labaw (Buh. 8:14).","response":"Kon ang pangulo sa nasod maoy ipadala sa senado alang sa usa ka misyon ngadto sa laing nasod nagpasabot lang kini sa kahinungdanon sa maong misyon apan dili nga mihunong na ang pagkapangulo sa presidente. Si Pedro nagtuman lang sa gisugo ni Cristo nga ang labaw maoy alagad sa tanan (Mat. 23:11)."},{"objection":"Dili tinuod nga dili masayop ang papa tungod kay sumala sa Kasulatan giingon nga ang tanang tawo makasasala (Jer. 10:23)","response":"Ang Sto. Papa dili “impeccable” kun dili makasala. Sama sa ubang mga sakop sa Iglesya kinahanglan gihapon nga siya nga makigbisog batok sa sala. Ang Sto. Papa “infallible” kun dili masayop diha sa iyang pagpanudlo opisyal alang sa tanan labot sa tuluhoan ug pamatasan\ntungod kay ang iyang aprobahan dinhi sa yuta aprobahan didto sa langit (Mat.16:19) ug si Jesus dili mahimong mo-aprobar og sayop nga pagtulon-an busa ang Ginoo mohatag gyod kaniya sa talagsaong panalipod aron dili siya makapanudlog sayop (Luc. 21:31-32)."},{"objection":"Si Pedro, nga giangkon sa mga katoliko nga una nilang papa, gisaway ni Pablo tungod kay nasayop siya (Gal.2:11).","response":"Ang pagsaway ni Pablo kang Pedro dili mahitungod sa doctrina ug moralidad kondili labot sa batasan nga gipakita ni Pedro didto sa Antioquia nga milikay sa pagkigsalo uban sa mga dili judio aron dili mahimangod ang iyang isigka-judio ngadto kaniya (Gal. 2:12). Kon si Pablo mibadlong ni Pedro dili sabton nga wala siya motamod sa katungod ni Pedro. Sa laing bahin si Pablo mibadlong ni Pedro kay nasayod siya nga tungod sa dako nga katungdanan nga gihuptan ni Pedro nga mas dakog influencia ngadto sa mga tawo ang mga buhat ni Pedro kay ni bisan kinsa."}]'::jsonb, '["Mat. 16:19","Isa. 22:21-22","Jn. 10:16","1 Ped. 5:1","Col. 1:18","Efeso 2:20","Mat. 16:18"]'::jsonb, '["primacy of peter"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.045Z')
