INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('holy-eucharist', 'ceb', 'sacraments', 'Ang Santos nga Eukaristiya', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa ang santos nga eukaristiya?', '"Ang Eukaristiya mao ang sacramento ug sakripisyo sa pagconsagrar sa pan ug bino aron mahimong lawas ug dugo ni Cristo. Matud ni Sto. Tomas de Aquino nga ang Eukaristiya mao ang kinalabwan sa tanang mga sacramento tungod kay diha sa Eukaristiya dili lamang nga madawat nato ang grasya nga atong gikinahanglan kondili madawat gyod nato si Cristo nga mao ang tighatag og grasya. Diha sa Eukaristiya atong madawat ang tibuok nga Cristo- ang iyang lawas, dugo, kalag ug pagka-Dios. Ang Eukaristiya mao ang kalan-on nga espirituhanon nga mohatag og kahimsog sa atong kalag. Ang Sta. Iglesya nagsugo sa mga matuohon sa pagkalawat nga takos labing menos makausa sa usa ka tuig.\n\nMaingon nato nga dunay tulo ka hugna sa pagtukod ni Cristo niining maong sacramento.\n\nUna- ang pag-andam sa katawhan. Nasayod si Jesus nga kining maong pagtulon-an mosukod gayod sa pagtuo sa iyang mga tinun-an busa si Jesus mihimog tulo ka dagkong milagro aron pagpasabot kanila sa iyang diosnong gahom. Ang unang milagro nga gihimo ni Jesus sa pagsugod niya sa iyang misyon mao ang pag-usab sa tubig ngadto sa bino (Jn. 2:1-11). Sunod nga milagro nga gihimo ni Jesus mao ang pagpakaon ang lima ka libo ka mga tawo gikan sa lima ka piraso nga pan ug duha ka piraso nga isda (Jn. 6:1-15) ug sa pagkasunod nianang gabii, sa paglakaw ibabaw sa tubig (Jn. 6:16-21). Pinaagi sa pagpadaghan sa pan ug isda ug paglakaw ibabaw sa tubig, iyang gipamatuod ang iyang gugma ug pagtagad ngadto kanila ug sa iyang gahom ibabaw sa balaod sa kinaiyahan. Busa iyang giandam ang ilang hunahuna ug kasingkasing sa pagtulon-an mahitungod sa langitnong kalan-on sa Santos nga Eukaristiya.\n\nIkaduha- mao ang saad sa Eukaristiya (Jn. 6:25-69). Sa pagkasunod adlaw, iyang gitudloan ang panon sa katawhan nga misunod ug nangita kaniya. Sa diha sila nangutana kaniya, “Magtutudlo, kanus-a ka pa mahiabot dinhi?” (v. 25) si Jesus nga nasayod sa ilang hunahuna mitubag, “Sultihan ko kamo: nangita kamo kanako kay nakakaon man kamo sa pan ug nangabusog ug dili tungod kay nakasabot kamo sa mga milagro nga akong nahimo” (v. 26). Sa hinayhinay gituboy ni Jesus ang ilang hunahuna gikan sa butang nga kalibotanon ngadto sa butang nga espirituhanon. Siya miingon “Ayaw kamo paghago alang sa kalan-on nga madunot, kondili sa kalan-on nga molungtad ngadto sa kinabuhing walay kataposan. Kining kalan-ona ihatag kaninyo sa Anak sa Tawo” (v. 27). Unya gipangutana nila siya, “Unsa may among buhaton aron pagtuman sa gisugo sa Dios?” (v. 28). Si Jesus mitubag, “Kini ang buluhaton nga ipabuhat sa Dios kaninyo: nga motuo kamo sa iyang gipadala” (v. 29). Niining tungora gipahimug-atan ni Jesus ang kahinungdanon sa pagtuo. Sila mitubag: “Unsa mang milagroha ang imong ipakita kanamo aron manuo kami kanimo? Ang among mga katigulangan nangaon ug mana didto sa kamingawan, sumala gayod sa giingon sa Kasulatan: Gihatagan niya silag pan gikan sa langit” (v. 30). Dinhi makita nato nga sama sa ubang okasyon ang mga judio mga tawo nga kulang sa pagtuo- buot silang makakita og milagro. Dili pa igo ang milagro nga ilang nasaksihan nga gibuhat ni Jesus. Ug kay si Jesus naghisgot man og kalan-on nga mohatod ngadto sa kinabuhing dayon buot nilang mohimo si Jesus og mas dako nga milagro kay sa nahitabo sa ilang mga katigulangan didto sa disyerto nga gipakaon sa mana.\n\nUg sa dihang sila miingon “Ginoo, hatagi kami kanunay niining maong kalan-on” (v. 34), si Jesus mipadayon sa pag-ingon “Ako mao ang pan nga naghatag sa kinabuhi. Ang moari kanako dili na gayod gutomon; ang motuo kanako dili na gayod uhawon” (v. 35). Ug iya silang gisultihan sa tin-aw gayod “Ug ang pan nga akong ihatag mao ang akong unod aron mabuhi ang kalibotan” (v. 51). Ug sa dihang misupak sila sa pag-ingon “Unsaon man niining tawhana sa paghatag kanato sa iyang lawas aron kan-on?” (v. 52). Siya mipahimug-at sa literal nga gipasabot sa kamatuoran sa iyang mga pulong sa pag-ingon nga dili lang kinahanglan nga sila mokaon sa iyang unod kondili kinahanglan nga sila moinom usab sa iyang dugo: “Ang mokaon sa akong unod ug moinom sa akong dugo may kinabuhing walay kataposan ug banhawon ko siya sa kataposang adlaw. Kay ang akong unod mao ang matuod nga kalan-on, ug ang akong dugo mao ang matuod nga ilimnon. Ang mokaon sa akong unod ug moinom sa akong dugo magpuyo dinhi kanako ug ako diha kaniya” (v. 54-56). Tungod niini daghan sa iyang mga tinun-an miingon “Lisod kaayong dawaton kining pagtulon-ana. Kinsa bay makasabot niini?” (v. 60) ug busa wala sila modawat niini. Ug si Jesus miingon ngadto kanila “Nakapabugnaw ba kini sa inyong pagtuo kanako” (v. 61) nga sa laing pagkasulti “nakalitan ba kamo sa akong gisulti?”\n\nKon (uban sa mga tigsupak) ang mga judio naghunahuna nga sa “pagkaon sa iyang unod ug pag-inom sa iyang dugo,” ang iya lamang gipasabot mao nga ilang dawaton ang iyang pagtulon-an diha sa ilang hunahuna ug kasingkasing, dili unta sila makugang. Ang mga judio nakalitan, tungod kay ilang gisabot nga si Jesus nahisgot gayod sa matuod nga pagkaon sa iyang unod ug pag-inom sa iyang dugo. Kon nasinayop pa nila pagsabot ang gisulti ni Jesus, Iya unta silang gipakita sa ilang kasaypanan sama sa iyang gihimo sa ubang okasyon (Mat. 16:5-12, Jn. 3:3-8, Jn. 11:11-14). Dili unta ni Jesus angkonon ang pagtulon-an nga ilang gipahid ngadto kaniya. Apan wala kini ipanghimakak ni Jesus. Sa laing bahin, siya misubli pagtudlo sa diosnong bili sa kalan-on nga ilang gisalikway. Ang eksakto nga mga pulong nga gilitok ni Jesus mao kining mosunod: a) “Nakapabugnaw ba kini kaninyo? Pananglit makita ninyo ang Anak sa Tawo nga mokayab balik sa iyang gigikanan?” (v. 61-62) nga nagpasabot “dili ba kamo makadawat sa akong gisulti? Dili ba lang gihapon kamo motuo kanako kon makita ninyo kining maong unod nga mosaka ngadto sa langit?” b) “Ang espiritu mao ang naghatag og kinabuhi, ang unod walay kapuslanan” (v. 63) nga nagpasabot “Ang espiritu sa akong pagka-Dios mao ang naghatag og kinabuhi, o makapahimo sa akong unod nga makahatag og kinabuhi nga kalan-on; ang ordinaryo nga unod sa tawo sama sa inyong gihunahuna walay kapuslanan.” c) “Ang mga pulong nga gisulti ko kaninyo-Espiritu ug kinabuhi” (v. 63) nga nagpasabot “nga ang mga pulong nga akong gisulti kaninyo usa ka saad alang kaninyo sa kalan-on nga makapahimo kaninyo nga usa kanako diha sa espiritu ug kinabuhi.” d) “apan pipila kaninyo wala manuo… mao nga gisultihan ko kamo nga walay makaari kanako gawas kon itugo kini sa Amahan” (v. 64-65) nga nagpasabot “nganong misupak man kamo kanako? Wala ba kamo motuo nga ako mao ang Anak sa Dios ug makahimo sa akong gisaad?”\n\nApan bisan pa niini ang mga judio wala matagbaw, tungod kay wala gihapon bakwia ni Jesus ang iyang sugo sa pagkaon sa iyang unod ug pag-inom sa iyang dugo. Ang kapandulan nagpabilin gihapon nga nag-ali sa ilang agianan; busa “daghan sa iyang mga tinun-an mibiya ug wala na gayod mokuyog kaniya” (v. 66). Busa miingon si Jesus sa 12 ka mga apostoles “Ug kamo, mobiya ba usab kamo kanako?” (v. 67). Si Simon Pedro mitubag kaniya, “Ginoo, kinsa may among kapaingnan? Anaa kanimo ang mga pulong nga naghatag og kinabuhing walay kataposan. Nagtuo kami ug nasayod nga ikaw mao ang Balaan sa Dios” (v. 68-69). Kining talamdon nga mga pulong, nga puno sa kamaunongon ug paghigugma, atong gisagop ingon nga atoa, uban sa pagpanaad sa pagkamatinumanon ngadto ni Jesus bisan kinsa pa ang motalikod kaniya.\n\nGituman ni Jesus ang iyang saad atol sa kataposang panihapon uban sa iyang napulog-duha ka mga apostoles. Iyang gipangandoy ang pag-abot sa maong takna: “Dako kaayo ang akong tinguha sa pagkaon uban kaninyo niining panihapon sa Pangilin sa Pagsaylo sa dili pa ako mag-antos” (Luc. 22:15). Unya “mikuha si Jesus sa pan, nagpasalamat sa Dios, ug gipikaspikas niya kini ug gihatag sa iyang mga tinun-an ug miingon “Dawata ninyo kini ug kan-a, kini ang akong lawas.” Unya gikuha niya ang kupa, nagpasalamat sa Dios, ug gihatag kanila ug miingon “Imna kini ninyong tanan, kini mao ang akong dugo nga naglig-on sa kasabotan, ang akong dugo nga giula alang sa tanang mga tawo aron ang mga sala mapasaylo” (Mat. 26:26-28). Si Jesus misulti niining mga pulonga sa usa ka labing solemne nga okasyon. Siya naghatag ngadto sa iyang mga tinun-an sa kataposan niyang pakigpulong, sa kataposan niyang tinguha ug kasugoan, kay sa pagkasunod adlaw siya paantoson ug patyon. Niining tungora naghatag siya ngadto sa iyang mga tinun-an sa ilang erensya kun kabilin o panulondon. Busa siya misulti kanila sa labing tin-aw ug dayag nga mga pulong. Ang mga pulong nga iyang gigamit sa ilang kaugalingon dili mahimong masaypan, ug labi na gayod kon lantawon ubos sa saad nga iyang gihimo nga iyang ihatag ang iyang unod aron kan-on ug ang iyang dugo aron imnon. Ang mga apostoles mituo, sama nga kita nagtuo, nga sa iyang pag-ingon “Kini ang akong lawas… Kini ang akong dugo,” nga ang pan ug bino nabalhin ngadto sa iyang mahal nga Lawas ug Dugo.\n\nAng pagtuo sa mga apostoles ug sa karaang Iglesya sa matuod nga presensya ni Cristo diha sa Santos nga Eukaristiya gipamatud-an sa mga bantugang tagsulat. Si San Ignatius sa Antioch (d. 117) miingon “Ang Eukaristiya mao ang Unod sa atong Manluluwas nga si Jesu-Cristo” (Epistola ad Smyrna c. 7). Si San Justin Martyr (d. 167) miingon “Ato kining gidawat dili ingon nga ordinaryo nga pan o ordinaryo nga bino, kondili si Jesu-Cristo ang atong Manluluwas… nga dunay Unod ug Dugo alang sa atong kaluwasan, ug busa kita usab gitudloan nga ang kalan-on nga gi-consagrahan pinaagi sa pulong sa pag-ampo gikan Kaniya… mao ang Unod ug Dugo ni Jesus nga nahimong tawo” (Apologia i.c. 66). Si San Irenaeus (d. 203) miingon “Ang pan ug bino pinaagi sa pulong sa Dios nabalhin ngadto sa Eukaristiya, nga mao ang Lawas ug Dugo ni Cristo” (Adversus Heresies v. 2,3). Si San Hippolytus sa Roma (d. 235) miingon “Siya naghatag kanato sa iyang kaugalingong diosnon nga Unod ug sa iyang kaugalingong bilihong Dugo aron kan-on ug imnon” (In Proverb, ix. 2). Ang maong santos nga pagtulon-an gidawat sa mga nagtuo ni Jesus sulod sa gatusan ka mga katuigan nga walay misupak hangtod sa pag-abot ni Berengarius nga miingon nga ang mga pulong “kini ang akong lawas” nagpasabot “Dili kini akong lawas apan simbolo lamang.” Kini maoy pag-ingon nga si Cristo wala gayod mohatag ngadto sa katawhan sa iyang Unod aron kan-on ug busa namakak sa iyang panaad nga gihimo. Kining maong interpretasyon nakahaling gilayon sa balaanong kasuko sa tibuok Simbahan; giisip ug giila kini nga supak sa karaang pagtuo sa Sta. Iglesya ug sa panudlo ni Cristo mismo; gibakwi kini sa nagpasiugda niining maong sayop nga panudlo nga namatay nga mahinulsolon.\n\nKinahanglan nga ato kanunayon nga paninguhaon ang pagdawat ni Cristo diha sa pagkalawat. Ang Eukaristiya 1) mohiusa nato kang Cristo “Ang mokaon sa akong unod ug moinom sa akong dugo magpuyo dinhi kanako ug ako diha kaniya” (Jn. 6:56), 2) mohatag kanato og dugang grasya, “ang mokaon kanako mabuhi tungod kanako” (Jn. 6:57), 3) mohiusa nato sa usag-usa “Sanglit may usa lamang ka pan, kitang tanan bisan daghan, usa lamang ka lawas, kay nakig-ambit man kita sa usa lamang ka pan” (1 Cor. 10:17), 4) ug naghupot sa saad sa pagkabanhaw “Ang mokaon sa akong unod ug moinom sa akong dugo may kinabuhing walay kataposan ug banhawon ko siya sa kataposang adlaw” (Jn. 6:54). Apan tungod kay diha sa pagkalawat, si Jesus man gayod ang atong pagadawaton kinahanglan usab nga mohimo kitag pagpangandam sa atong kalag “Busa ang mokaon sa pan sa Ginoo ug moinom sa iyang kupa sa paagi nga dili takos, nakasala batok sa lawas ug sa dugo sa Ginoo” (1 Cor. 11:27)."'::jsonb, '[{"objection":"Ang pag-ingon ni Jesus nga siya ang pan sa kinabuhi (Jn. 6:35) dili literal kondili usa ka sambingay sama sa iyang pag-ingon nga siya ang punoan sa paras (Jn. 15:1).","response":"Sa pag-ingon ni Jesus nga siya ang punoan sa paras ug kita ang mga sanga (Jn. 15:1) klaro nga usa kini ka sambingay kay masabot man nato ang duha ka kamatuoran nga gitandi nga sama nga ang mga sanga nabuhi tungod sa punoan ang mga magtutuo nabuhi tungod ni Jesus, samtang sa laing bahin si Jesus mipasabot nga ang pan nga iyang ihatag mao ang iyang unod (Jn. 6:51) nga kinahanglan nga atong kan-on aron kita mabuhi (Jn. 6:53) busa ang panagtandi dili magamit."},{"objection":"Ang pagkaon sa iyang unod dili sabton nga literal nga unod tungod kay ang unod walay kapuslanan (Jn. 6:63) kondili ang pagdawat sa iyang pagtulon-an ug ang pagtuo kaniya (Jn. 6:35).","response":"Ang pagkaon sa unod kon sabton sa dili literal nga pagsabot nagkahulogan og pagpanimalos, pagdagmal o pagpatay (Eze. 5:10, Isa. 49:26, Miq. 3:3) nga dili mahimo nga mao ang sentido nga gipasabot ni Jesus. Ang ordinaryo nga unod sa tawo nga maoy naa sa panabot sa mga judio mao ang way kapuslanan (Jn. 6:63) apan ang unod ug dugo ni Cristo tungod kay kini nahiusa man sa iyang pagka-Dios makahatag og kinabuhi (Jn. 6:54-56)."},{"objection":"Ang pan ug bino simbolo lamang sa lawas ug dugo ni Cristo ug dili literal sama nga si Jesus miingon nga siya ang pultahan (Jn. 10:9) dili sabton nga literal nga nahimo siya nga pultahan.","response":"Dili mahitabo nga sa kataposang panihapon si Jesus magsulti ug sambingay: 1) tungod sa ka-solemne sa maong okasyon; 2) tungod kay si Jesus nasayod nga ang iyang mga tinun-an hinay nga mosabot; 3) si Jesus, tungod kay siya Dios, nasayod sa mahimong sangpotanan sa iyang gipamulong, nga dili maihap ang katawhan sa umaabot nga panahon nga magsimba kaniya ubos sa bayhon sa pan; ug ikaupat- ang mga apostoles nagpahayag sa ilang pagtuo sa matuod nga presensya ni Cristo diha sa Eukaristiya “Ang kupa sa panalangin nga tungod niini gipasalamatan nato ang Dios-dili ba kini pakig-ambit man nato sa dugo ni Cristo inig-inom nato gikan niining kupa? Ug dili ba pakig-ambit man nato sa lawas ni Cristo inigkaon nato niining pan nga atong gipikaspikas?” (1 Cor.10:16). Diha sa consagrasyon, dili si Cristo ang nahimong pan kondili ang substancia sa pan maoy nabalhin ngadto sa buhi nga lawas ni Cristo samtang ang bayhon sa pan ug bino nagpabilin."}]'::jsonb, '["Luc. 22:15","Mat. 26:26-28","Jn. 6:56","Jn. 6:57","1 Cor. 10:17","Jn. 6:54","1 Cor. 11:27","1 Cor.10:16"]'::jsonb, '["holy eucharist"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.046Z')
