INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('dietary-abstinence', 'ceb', 'church-teaching', 'Kalan-on nga Gidili', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa kalan-on nga gidili?', '"Ang Sta. Iglesya nagtudlo nga ang tanang butang nga gibuhat sa Dios maayo, \"Maayo ang tanang gibuhat sa Dios; ang tanan angay nga dawaton uban ang pagpasalamat, ug walay isalikway bisan unsa, kay ang pulong sa Dios ug ang pag-ampo maoy nakapabalaan niini\" (1 Tim. 4:4-5). Apan diha sa Daang Tugon dunay pipila ka mga kalan-on nga gidili sa Dios ug giisip nga mahugaw alang sa iyang katawhan. Kini nga disiplina gihimo sa Dios aron: 1) sa pagpalahi sa iyang katawhan gikan sa ubang mga nasod nga naglibot kanila, 2) sa pagsulay sa ilang pagkamasinugtanon sa iyang mga balaod, 3) pagtudlo kanila sa unang mga pagtulon-an sa pagputli sa kaugalingon. Diha sa Bag-ong Tugon gipahunong na ni Cristo ang balaod mahitungod sa mga gidili nga kalan-on aron pagpahimug-at sa tinuod nga makapahugaw sa tawo nga mao ang sala."'::jsonb, '[{"objection":"Diha sa Biblia gidili ang pagkaog dugo tungod kay kini tinubdan sa kinabuhi, “Makakaon kamo sa tanang mananap ug sa lunhawng mga tanom kay gitugyan ko kini kaninyo aron mahimong pagkaon ninyo. Usa lamang ka butang nga kinahanglan dili ninyo kan-on, ug kini mao ang karne nga may dugo pa kay ang kinabuhi anaa man sa dugo” (Gen. 9:3-4). Adunay talaan sa mga kalan-on nga gidili, “Apan ayaw ninyo kan-a ang kamelyo, ang koneho o ang liebre. Kinahanglan nga isipon nga hugaw kining mga mananapa… Ang baboy bisan tuod kon pikas ang kuko niini, dili man kini mousap, busa hugaw kini alang kaninyo… apan bisan unsa nga anaa sa kadagatan ug sa mga suba ug sa katubigan nga walay mga kapay ug mga himbis dili angayng kan-on” (Lev. 11:1-31). Dili sila ipakaon kay mahugaw ug dili binalaan nga hayop, “Ilhon ninyo ang kalainan sa balaan ug sa dili balaan, ug ang kalainan sa hugaw ug sa hinlo” (Lev. 10:10). Ang dugo dili ipakaon kay gamiton sa paghalad sa mga sala, “kay ang kinabuhi anaa sa dugo, ug gihatag ko kini kaninyo aron gamiton sa pagpapas sa sala” (Lev. 17:11). Bisan sa Bag-ong tugon nagpadayon kining maong balaod, “Ayaw kamo pagkaon sa kalan-on nga gihalad ngadto sa mga diosdios, ni dugo, ni mananap nga gituok” (Buh. 15:29).","response":"Dili absoluto nga gidili gyod sa Dios ang pagkaon og dugo, “Ug sanglit ang dugo niini wala man dad-a sulod sa sanctuario, inyo unta kining gikaon didto sa sanctuario sumala sa akong sugo” (Lev. 10:18). Dunay okasyon nga ang katawhan sa Dios mikaon sa dugo apan wala sila makasala, “Nag-ilogay ang mga tawo sa mga butang nga gipamiyaan sa mga kaaway, ug nanakop silag mga karnero ug mga baka, ug ilang giihaw kini ug ilang gikaon lakip ang dugo… Kon ako ang nakasala o si Jonatan, ipakita ang Urim, apan kon ang nakasala mao ang katawhan sa Israel, ang Tumim maoy ipakita. Apan ang natungnan sa ripa mao si Jonatan ug si Saul” (1 Sam. 14:32, 41). Diha sa Bag-ong Tugon gipahayag ni Jesus nga mahimong kan-on ang tanang pagkaon, “Bisan unsa nga mosulod sa baba sa tawo dili makapahugaw kaniya, kay kini dili man mosulod sa iyang kasingkasing, kondili ngadto sa iyang tiyan, ug unya mogula usab sa lawas. Sa pagsulti ni Jesus niini, iyang gipahayag nga mahimong kan-on ang tanang pagkaon” (Mar. 7:18-19). Si Jesus miingon usab, “kaon kamo sa tanan nga idulot kaninyo” (Luc. 10:8). Si Pedro gipakitaan sa Dios ug habol diin didto ang tanang hayop nga dunay upat ka tiil ug nagsaguyod sa yuta ug ang Dios misugo kaniya, \"Pedro, tindog; pag-ihaw ug kaon.\" Sa dihang si Pedro mitubag, \"Dili ko, Ginoo, kay sukad masukad wala ako makakaon ug bisan unsa nga mahugaw\" ang Ginoo miingon kaniya, \"Ayaw isipa nga mahugaw ang giila sa Dios nga malinis\" (Buh. 11:5-9). Duha ka panudlo ang atong makuha gikan niini. 1) nga gihinloan na sa Dios kadtong mga giisip nga mahugaw nga kalan-on sa Daang Tugon. 2) gigamit kini nga okasyon aron sa pagpasabot nga bisan ang mga hentil nga kaniadto giisip usab nga mahugaw gidawat na sa Dios.\nAng nahitabo sa panahon sa mga apostoles mao nga anaa pa sila sa pagbiya sa ilang tinuhoan nga judaismo ngadto sa tinuhoan nga kristianismo busa dili katingad-an nga sa kasinugdanan dunay mga balaod sa tinuhoang judaismo ang ila gihapon nga gipatuman. Aron ang mga dili judio dili mabug-atan sa pagtuman niini nga mga balaod ang mga apostoles uban sa mga kadagkoan didto sa Jerusalem nagkauyon nga dili ang tanan nga gibansay sa mga judio ang ila usab nga ipatuman sa mga dili judio kondili ang pipila lamang ka mga tulomanon. Si Santiago mipahayag, “Ang akong hunahuna mao nga dili nato samokon ang mga dili Judio nga midawat sa Dios. Hinunoa, ato silang sulatan nga dili sila mangaon sa mahugaw nga mga kalan-on tungod kay kini gihalad man ngadto sa mga diosdios… ug nga dili sila mangaon sa bisan unsang mananap nga gituok, ug sa bisan unsang dugo” (Buh. 15:19-20). Apan paglabay sa panahon, ilang gitudlo ang kausaban nga gitudlo sa Dios. Si San Pablo nagsulat, “Ang mokaon bisag unsa dili angay nga maghukom sa tawo nga utanon ray kan-on; ug ang tawo usab nga utanon ray kan-on, dili angay maghukom sa tawo nga mokaon bisag unsa, kay gidawat na siya sa Dios” (Rom. 14:3). Mahugaw lang ang pagkaon alang niadtong may mahugaw nga hunahuna, “Apan kon may nagtuo nga hugaw ang usa ka butang, hugaw kini alang kaniya” (Rom. 14:14) ug si San Pablo midapadayon, “Kay ang Gingharian sa Dios dili pagkaon ug pag-inom, kondili pagkamatarong, pakigdait, ug kalipay nga gihatag sa Espiritu Santo” (Rom. 14:17). Ang pagkaon ug ang dili pagkaon sa gidili wala nay labot sa kaluwasan, “Hinuon, ang pagkaon dili makapaduol kanato sa Dios ni makadaot kanato kon dili kita mokaon, ni makaayo kanato kon mokaon kita niini” (1 Cor. 8:8). Ipakaon na ang tanang gibaligya sa tindahan sa pagkaon, “Makahimo kamo pagkaon bisan unsang karne nga gibaligya diha sa merkado, sa walay pag-agad sa inyong konsensya… Busa kon mokaon kamo o moinom kamo o magbuhat bisan unsa, buhata ang tanan sa pagpasidungog sa Dios” (1 Cor. 10:25, 31). Si San Pablo nagtudlo usab nga dili na kita pagahukman sumala sa pagkaon, “Busa ayaw ninyo itugot nga may magsaway kaninyo sa inyong kan-on o imnon… Kining tanan mga landong lamang sa mga butang nga umaabot, apan ang katumanan mao si Cristo” (Col. 2:16-17). Angay natong paminawon kining nasulat sa tag-Hebreo: “Ayaw itugot nga ang lahi nga mga pagtulon-an makapatipas kaninyo gikan sa matarong agianan. Maayo gayod nga malig-on ang atong kalag pinaagi sa grasya sa Dios, ug dili pinaagi sa mga tulomanon mahitungod sa kalan-on kay wala makatabang ang maong tulomanon niadtong nagtuman niini” (Heb. 13:9)."}]'::jsonb, '["1 Tim. 4:4-5","Gen. 9:3-4","Lev. 11:1-31","Lev. 10:10","Lev. 17:11","Buh. 15:29","Lev. 10:18","1 Sam. 14:32, 41","Mar. 7:18-19","Luc. 10:8","Buh. 11:5-9","Buh. 15:19-20","Rom. 14:3","Rom. 14:14","Rom. 14:17","1 Cor. 8:8","1 Cor. 10:25, 31","Col. 2:16-17","Heb. 13:9"]'::jsonb, '["dietary abstinence"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.048Z')
